  1	import { type FC, useEffect, useState } from 'react';
  2	
  3	import {
  4	  Alert,
  5	  Button,
  6	  FileUpload,
  7	  Form,
  8	  FormGroup,
  9	  HelperText,
 10	  HelperTextItem,
 11	  Stack,
 12	  StackItem,
 13	} from '@patternfly/react-core';
 14	import { useForkliftTranslation } from '@utils/i18n';
 15	
 16	import { useVddkBuildImage } from './hooks/useVddkBuildImage';
 17	import { getUploadButtonText, uploadVddkTarball } from './utils/utils';
 18	
 19	type VddkUploaderProps = {
 20	  onChangeVddk: (value: string) => void;
 21	};
 22	
 23	const VddkUploader: FC<VddkUploaderProps> = ({ onChangeVddk }) => {
 24	  const { t } = useForkliftTranslation();
 25	  const [file, setFile] = useState<File | undefined>();
 26	  const [filename, setFilename] = useState('');
 27	  const [buildName, setBuildName] = useState('');
 28	  const [error, setError] = useState<string | null>(null);
 29	  const [uploading, setUploading] = useState(false);
 30	
 31	  const vddkBuild = useVddkBuildImage(buildName);
 32	  const { body, isBuildFailed, isBuilding, isBuildSucceeded, title, variant } = vddkBuild ?? {};
 33	
 34	  useEffect(() => {
 35	    if (isBuildSucceeded) onChangeVddk(body!);
 36	  }, [body, isBuildSucceeded, onChangeVddk]);
 37	
 38	  const handleUpload = async () => {
 39	    if (!file) return;
 40	
 41	    setError(null);
 42	    setUploading(true);
 43	    setBuildName('');
 44	
 45	    try {
 46	      const response = await uploadVddkTarball(file);
 47	      setBuildName(response?.['build-name']);
 48	    } catch (err) {
 49	      setError((err as Error).message);
 50	    } finally {
 51	      setUploading(false);
 52	    }
 53	  };
 54	
 55	  return (
 56	    <Form>
 57	      <FormGroup label={t('VDDK init image archive')} isRequired={false}>
 58	        <FileUpload
 59	          id="vddk-file"
 60	          filename={filename}
 61	          onFileInputChange={(_, newFile) => {
 62	            if (newFile) {
 63	              setFile(newFile);
 64	              setFilename(newFile.name);
 65	            }
 66	          }}
 67	          hideDefaultPreview
 68	          isRequired
 69	          onClearClick={() => {
 70	            setFile(undefined);
 71	            setFilename('');
 72	          }}
 73	        />
 74	        <HelperText>
 75	          <HelperTextItem variant="indeterminate">
 76	            {t('Upload a VDDK archive and build a VDDK init image from it.')}
 77	          </HelperTextItem>
 78	        </HelperText>
 79	      </FormGroup>
 80	
 81	      <Stack hasGutter>
 82	        <StackItem>
 83	          <Button
 84	            isLoading={uploading || isBuilding}
 85	            onClick={handleUpload}
 86	            isDisabled={!file || uploading || isBuilding}
 87	          >
 88	            {getUploadButtonText(uploading, isBuilding)}
 89	          </Button>
 90	        </StackItem>
 91	
 92	        {error && (
 93	          <StackItem>
 94	            <Alert variant="danger" title={t('Error')}>
 95	              {error}
 96	            </Alert>
 97	          </StackItem>
 98	        )}
 99	
100	        {isBuildFailed && (
101	          <Alert variant={variant} title={title}>
102	            {body}
103	          </Alert>
104	        )}
105	      </Stack>
106	    </Form>
107	  );
108	};
109	
110	export default VddkUploader;

